import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void twoClusters() {
        char[][] grid = {
            {'1','1','0','0'},
            {'1','0','0','1'},
            {'0','0','1','1'}
        };
        assertEquals(2, new Solution().numIslands(grid));
    }

    @Test
    void entireGridOneIsland() {
        char[][] grid = {
            {'1','1','1'},
            {'1','1','1'}
        };
        assertEquals(1, new Solution().numIslands(grid));
    }

    @Test
    void allWater() {
        char[][] grid = {
            {'0','0'},
            {'0','0'}
        };
        assertEquals(0, new Solution().numIslands(grid));
    }

    @Test
    void singleLandCell() {
        char[][] grid = {{'1'}};
        assertEquals(1, new Solution().numIslands(grid));
    }

    @Test
    void emptyGrid() {
        char[][] grid = {};
        assertEquals(0, new Solution().numIslands(grid));
    }

    @Test
    void diagonalCellsAreNotConnected() {
        // Diagonal cells do not count as 4-directional neighbors
        char[][] grid = {
            {'1','0','1'},
            {'0','1','0'},
            {'1','0','1'}
        };
        assertEquals(5, new Solution().numIslands(grid));
    }

    @Test
    void singleRowManyIslands() {
        char[][] grid = {{'1','0','1','0','1'}};
        assertEquals(3, new Solution().numIslands(grid));
    }
}
